content:
## 行动者

- id: {{ actor.id }}
- 姓名: {{ actor.name }}
- 描述: {{ actor.description }}
- 公开状态: {{ actor.public_state }}
- 当前活动: {{ actor.current_activity.name }}

## 世界

- id: {{ world.id }}
- 名称: {{ world.name }}
- language: {{ world.language }}

## 模拟

- id: {{ simulation.id }}
- 当前时间: {{ simulation.current_time }}

## 地点

- id: {{ location.id }}
- 名称: {{ location.name }}
- 描述: {{ location.description }}

## 行动者库存

{% for entry in inventory %}
- stack id: {{ entry.stack_id }}; item id: {{ entry.item_id }}; {{ entry.name }} x{{ entry.quantity }}{% if entry.quality %}; 品质: {{ entry.quality }}{% endif %}; 描述: {{ entry.description }}
{% else %}
- 无
{% endfor %}

## 行动者装备

{% for entry in equipment %}
- id: {{ entry.id }}; {{ entry.name }}; 已装备: {{ entry.equipped }}{% if entry.equipped_position %}; 部位: {{ entry.equipped_position }}{% endif %}; 描述: {{ entry.description }}{% if entry.quality %}; 品质: {{ entry.quality }}{% endif %}
{% else %}
- 无
{% endfor %}

## 同地点范围内的角色

{% for entry in perceived_characters %}
- id: {{ entry.character.id }}; 姓名: {{ entry.character.name }}; 地点: {{ entry.location.name }}{% if entry.position %}; 位置: {{ entry.position }}{% endif %}{% if entry.landmark %}; 地标: {{ entry.landmark.name }}{% endif %}; 公开状态: {{ entry.character.public_state }}; 描述: {{ entry.character.description }}
{% else %}
- 无
{% endfor %}

## 此地点的背景角色

{% for entry in perceived_background_characters %}
- id: {{ entry.character.id }}; 姓名: {{ entry.character.name }}; 地点: {{ entry.location.name }}{% if entry.position %}; 位置: {{ entry.position }}{% endif %}{% if entry.landmark %}; 地标: {{ entry.landmark.name }}{% endif %}; 描述: {{ entry.character.description }}
{% else %}
- 无
{% endfor %}

## 此地点的物品堆叠

{% for entry in perceived_items %}
- stack id: {{ entry.stack.id }}; item id: {{ entry.item.id }}; {{ entry.item.name }} x{{ entry.stack.quantity }}{% if entry.stack.quality %}; 品质: {{ entry.stack.quality }}{% endif %}{% if entry.position %}; 位置: {{ entry.position }}{% endif %}{% if entry.owner_id %}; owner id: {{ entry.owner_id }}{% endif %}; 描述: {{ entry.item.description }}
{% else %}
- 无
{% endfor %}

## 此地点的装备

{% for entry in perceived_equipment %}
- id: {{ entry.equipment.id }}; {{ entry.equipment.name }}{% if entry.position %}; 位置: {{ entry.position }}{% endif %}{% if entry.owner_id %}; owner id: {{ entry.owner_id }}{% endif %}; 描述: {{ entry.equipment.description }}{% if entry.equipment.quality %}; 品质: {{ entry.equipment.quality }}{% endif %}
{% else %}
- 无
{% endfor %}

## 此地点的容器

{% for entry in perceived_containers %}
- id: {{ entry.container.id }}; {{ entry.container.name }}; state: {{ entry.container.state }}{% if entry.position %}; 位置: {{ entry.position }}{% endif %}{% if entry.owner_id %}; owner id: {{ entry.owner_id }}{% endif %}; 描述: {{ entry.container.description }}
{% else %}
- 无
{% endfor %}

## 此地点的地标

{% for landmark in perceived_landmarks %}
- id: {{ landmark.id }}; {{ landmark.name }}; 描述: {{ landmark.description }}
{% else %}
- 无
{% endfor %}

## 确定性分段的用户输入

{% for segment in input_segments %}
Segment {{ segment.index }}:
- type: {{ segment.type }}
{% if segment.type == "ooc" %}
- command text: {{ segment.command_text }}
{% endif %}
- source text:
{{ segment.source_text }}

{% else %}
没有提供非空输入片段。
{% endfor %}

## 原始用户输入

{{ user_input }}
